import { Component, OnInit } from '@angular/core';
import { FaturamentoService } from '../../services/faturamento.service';
import { EstoqueService } from '../../services/estoque.service';
import { NotaFiscal, Produto, CriarNotaFiscalItemRequest } from '../../models';

@Component({
  selector: 'app-notas-fiscais',
  templateUrl: './notas-fiscais.component.html',
  styleUrls: ['./notas-fiscais.component.css']
})
export class NotasFiscaisComponent implements OnInit {
  notas: NotaFiscal[] = [];
  produtos: Produto[] = [];
  loading = false;
  imprimindo = false;
  error = '';
  success = '';
  showForm = false;
  mostrarApenasAbertas = true;

  itens: CriarNotaFiscalItemRequest[] = [];
  produtoSelecionado: Produto | null = null;
  quantidadeSelecionada = 0;
  idempotencyKey: string = this.gerarUUID();

  filtroNumero: string = '';
  filtroStatus: string = '';
  filtroData: string = '';

  // Paginação
  paginaAtual = 1;
  registrosPorPagina = 10;
  ordem: 'asc' | 'desc' = 'desc';
  ordenarPor: 'numero' | 'status' | 'data' = 'data';

  get notasAbertas(): NotaFiscal[] {
    let notas = this.mostrarApenasAbertas 
      ? this.notas.filter(nota => nota.status === 'Aberta')
      : this.notas;

    // Aplicar filtros
    if (this.filtroNumero) {
      notas = notas.filter(nota => 
        nota.numeroSequencial.toString().includes(this.filtroNumero)
      );
    }

    if (this.filtroStatus && this.filtroStatus !== '') {
      notas = notas.filter(nota => nota.status === this.filtroStatus);
    }

    if (this.filtroData) {
      notas = notas.filter(nota => 
        nota.dataCriacao.split('T')[0] === this.filtroData
      );
    }

    return notas;
  }

  alternarFiltro(): void {
    this.mostrarApenasAbertas = !this.mostrarApenasAbertas;
  }

  limparFiltros(): void {
    this.filtroNumero = '';
    this.filtroStatus = '';
    this.filtroData = '';
  }

  constructor(
    private faturamentoService: FaturamentoService,
    private estoqueService: EstoqueService
  ) { }

  ngOnInit(): void {
    this.carregarNotas();
    this.carregarProdutos();
  }

  carregarNotas(): void {
    this.loading = true;
    this.error = '';
    this.faturamentoService.obterTodasNotas().subscribe({
      next: (data) => {
        this.notas = data;
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Erro ao carregar notas: ' + (err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }

  carregarProdutos(): void {
    this.estoqueService.obterTodosProdutos().subscribe({
      next: (data) => {
        this.produtos = data;
      },
      error: (err) => {
        this.error = 'Erro ao carregar produtos: ' + (err.message || 'Erro desconhecido');
      }
    });
  }

  abrirFormulario(): void {
    this.showForm = true;
    this.itens = [];
    this.idempotencyKey = this.gerarUUID();
    this.produtoSelecionado = null;
    this.quantidadeSelecionada = 0;
  }

  gerarUUID(): string {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  }

  fecharFormulario(): void {
    this.showForm = false;
    this.itens = [];
    this.produtoSelecionado = null;
    this.quantidadeSelecionada = 0;
  }

  adicionarItem(): void {
    if (!this.produtoSelecionado || this.quantidadeSelecionada <= 0) {
      this.error = 'Selecione um produto e uma quantidade válida';
      return;
    }

    const itemExistente = this.itens.find(i => i.produtoId === this.produtoSelecionado!.id);
    if (itemExistente) {
      itemExistente.quantidade += this.quantidadeSelecionada;
    } else {
      this.itens.push({
        produtoId: this.produtoSelecionado.id,
        quantidade: this.quantidadeSelecionada
      });
    }

    this.produtoSelecionado = null;
    this.quantidadeSelecionada = 0;
    this.error = '';
  }

  removerItem(produtoId: number): void {
    this.itens = this.itens.filter(i => i.produtoId !== produtoId);
  }

  obterNomeProduto(produtoId: number): string {
    const produto = this.produtos.find(p => p.id === produtoId);
    return produto ? produto.descricao : 'Produto desconhecido';
  }

  obterSaldoProduto(produtoId: number): number | null {
    const produto = this.produtos.find(p => p.id === produtoId);
    return produto ? produto.saldo : null;
  }

  temSaldoSuficiente(produtoId: number, quantidade: number): boolean {
    const saldo = this.obterSaldoProduto(produtoId);
    return saldo !== null && saldo >= quantidade;
  }

  notaPodeSerImpresa(): boolean {
    return this.itens.every(item => this.temSaldoSuficiente(item.produtoId, item.quantidade));
  }

  deletarNota(id: number): void {
    if (!confirm('Tem certeza que deseja deletar esta nota fiscal?')) {
      return;
    }

    this.loading = true;
    this.error = '';

    this.faturamentoService.deletarNotaFiscal(id).subscribe({
      next: () => {
        this.success = 'Nota fiscal deletada com sucesso!';
        this.carregarNotas();
        setTimeout(() => this.success = '', 3000);
      },
      error: (err) => {
        this.error = 'Erro ao deletar nota: ' + (err.error?.erro || err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }

  criarNotaFiscal(): void {
    if (this.itens.length === 0) {
      this.error = 'A nota fiscal deve ter pelo menos um item';
      return;
    }

    this.loading = true;
    this.error = '';
    this.success = '';

    this.faturamentoService.criarNotaFiscal({ itens: this.itens, idempotencyKey: this.idempotencyKey }).subscribe({
      next: () => {
        this.success = 'Nota fiscal criada com sucesso!';
        this.carregarNotas();
        this.fecharFormulario();
        setTimeout(() => this.success = '', 3000);
      },
      error: (err) => {
        this.error = 'Erro ao criar nota: ' + (err.error?.erro || err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }

  imprimirNotaFiscal(id: number): void {
    const nota = this.notas.find(n => n.id === id);
    if (!nota) return;

    if (nota.status !== 'Aberta') {
      this.error = 'Apenas notas abertas podem ser impressas';
      return;
    }

    if (!confirm(`Deseja imprimir a nota fiscal nº ${nota.numeroSequencial}?`)) {
      return;
    }

    this.imprimindo = true;
    this.error = '';
    this.success = '';

    this.faturamentoService.imprimirNotaFiscal(id).subscribe({
      next: (response) => {
        this.success = response.mensagem || 'Nota fiscal impressa com sucesso!';
        this.carregarNotas();
        this.imprimindo = false;
        setTimeout(() => this.success = '', 3000);
      },
      error: (err) => {
        this.error = 'Erro ao imprimir nota: ' + (err.error?.erro || err.message || 'Erro desconhecido');
        this.imprimindo = false;
      }
    });
  }
}
<div class="container">
  <h1>Notas Fiscais</h1>

  <div *ngIf="error" class="error-message">
    {{ error }}
  </div>

  <div *ngIf="success" class="success-message">
    {{ success }}
  </div>

  <div *ngIf="imprimindo" class="spinner">
    🔄 Processando impressão... (com tentativas automáticas de reconexão)
  </div>

  <div *ngIf="loading && !showForm" class="spinner">
    Carregando...
  </div>

  <button (click)="abrirFormulario()" class="btn btn-primary" *ngIf="!showForm && !loading">
    + Nova Nota Fiscal
  </button>

  <div *ngIf="!showForm && !loading && notas.length > 0" class="filter-buttons">
    <button 
      (click)="alternarFiltro()" 
      class="btn btn-secondary"
      [class.active]="mostrarApenasAbertas">
      {{ mostrarApenasAbertas ? '📋 Apenas Abertas' : '📊 Todas as Notas' }}
    </button>
  </div>

  <!-- Filtros de Busca -->
  <div *ngIf="!showForm && !loading && notas.length > 0" class="filters-container">
    <div class="filter-group">
      <label>🔍 Número:</label>
      <input 
        type="text" 
        [(ngModel)]="filtroNumero" 
        placeholder="Buscar por número"
        class="filter-input">
    </div>

    <div class="filter-group">
      <label>Status:</label>
      <select [(ngModel)]="filtroStatus" class="filter-input">
        <option value="">Todos</option>
        <option value="Aberta">Aberta</option>
        <option value="Fechada">Fechada</option>
      </select>
    </div>

    <div class="filter-group">
      <label>📅 Data:</label>
      <input 
        type="date" 
        [(ngModel)]="filtroData" 
        class="filter-input">
    </div>

    <button (click)="limparFiltros()" class="btn btn-secondary" *ngIf="filtroNumero || filtroStatus || filtroData">
      ✖️ Limpar Filtros
    </button>
  </div>

  <div *ngIf="showForm" class="form-container">
    <h2>Nova Nota Fiscal</h2>

    <div class="form-group">
      <label>Produto:</label>
      <select [(ngModel)]="produtoSelecionado" class="form-input">
        <option [ngValue]="null">Selecione um produto</option>
        <option *ngFor="let p of produtos" [ngValue]="p">
          {{ p.descricao }} (Saldo: {{ p.saldo }})
        </option>
      </select>
    </div>

    <div class="form-group">
      <label>Quantidade:</label>
      <input type="number" [(ngModel)]="quantidadeSelecionada" class="form-input" min="1" />
    </div>

    <button (click)="adicionarItem()" class="btn btn-secondary">+ Adicionar Item</button>

    <div *ngIf="itens.length > 0" class="itens-container">
      <h3>Itens da Nota</h3>
      <table class="table">
        <thead>
          <tr>
            <th>Produto</th>
            <th>Quantidade</th>
            <th>Ação</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let item of itens">
            <td>{{ obterNomeProduto(item.produtoId) }}</td>
            <td>{{ item.quantidade }}</td>
            <td>
              <button (click)="removerItem(item.produtoId)" class="btn btn-small btn-danger">
                Remover
              </button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <div class="form-buttons">
      <button (click)="criarNotaFiscal()" class="btn btn-success" [disabled]="itens.length === 0">
        Criar Nota Fiscal
      </button>
      <button (click)="fecharFormulario()" class="btn btn-secondary">Cancelar</button>
    </div>
  </div>

  <div *ngIf="!showForm && !loading && notasAbertas.length > 0" class="table-container">
    <table class="table">
      <thead>
        <tr>
          <th>ID</th>
          <th>Número</th>
          <th>Status</th>
          <th>Data Criação</th>
          <th>Itens</th>
          <th>Ações</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let nota of notasAbertas">
          <td>{{ nota.id }}</td>
          <td>#{{ nota.numeroSequencial }}</td>
          <td>
            <span [class.status-aberta]="nota.status === 'Aberta'" 
                  [class.status-fechada]="nota.status === 'Fechada'">
              {{ nota.status }}
            </span>
          </td>
          <td>{{ nota.dataCriacao | date: 'dd/MM/yyyy HH:mm' }}</td>
          <td>
            <div *ngFor="let item of nota.itens" [class.saldo-insuficiente]="!temSaldoSuficiente(item.produtoId, item.quantidade)">
              {{ obterNomeProduto(item.produtoId) }} | Estoque: {{ obterSaldoProduto(item.produtoId) ?? 'N/A' }} | Solicitado: {{ item.quantidade }}
            </div>
          </td>
          <td>
            <button 
              (click)="imprimirNotaFiscal(nota.id)" 
              class="btn btn-small btn-success"
              [disabled]="nota.status !== 'Aberta' || imprimindo || !notaPodeSerImpresa()"
              [title]="!notaPodeSerImpresa() ? 'Saldo insuficiente para alguns produtos' : ''">
              🖨️ Imprimir
            </button>
            <button 
              (click)="deletarNota(nota.id)" 
              class="btn btn-small btn-danger"
              [disabled]="imprimindo">
              🗑️ Deletar
            </button>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="!showForm && !loading && notasAbertas.length === 0" class="empty-message">
    {{ mostrarApenasAbertas ? 'Nenhuma nota fiscal aberta para impressão.' : 'Nenhuma nota fiscal cadastrada.' }}
  </div>
</div>
